export function parseAddCollateralInstruction<
  TProgram extends string,
  TAccountMetas extends readonly AccountMeta[],
>(
  instruction: Instruction<TProgram> &
    InstructionWithAccounts<TAccountMetas> &
    InstructionWithData<ReadonlyUint8Array>,
): ParsedAddCollateralInstruction<TProgram, TAccountMetas> {
  if (instruction.accounts.length < 16) {
    throw new SolanaError(
      SOLANA_ERROR__PROGRAM_CLIENTS__INSUFFICIENT_ACCOUNT_METAS,
      {
        actualAccountMetas: instruction.accounts.length,
        expectedAccountMetas: 16,
      },
    );
  }
  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      owner: getNextAccount(),
      fundingAccount: getNextAccount(),
      perpetuals: getNextAccount(),
      pool: getNextAccount(),
      position: getNextAccount(),
      market: getNextAccount(),
      targetCustody: getNextAccount(),
      targetOracleAccount: getNextAccount(),
      collateralCustody: getNextAccount(),
      collateralOracleAccount: getNextAccount(),
      collateralCustodyTokenAccount: getNextAccount(),
      fundingTokenProgram: getNextAccount(),
      eventAuthority: getNextAccount(),
      program: getNextAccount(),
      ixSysvar: getNextAccount(),
      fundingMint: getNextAccount(),
    },
    data: getAddCollateralInstructionDataDecoder().decode(instruction.data),
  };
}
